PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?year
WHERE {
  wd:Q8683 wdt:P268 ?event;
  ?event wdt:P585 ?year.
}
ORDER BY DESC(?year)
LIMIT 1

